class Solution:
    def removeInvalidParentheses(self, s: str) -> List[str]:
        res = set()
        def backtrack(index, count, current):
            if index == len(s):
                if count == 0:
                    res.add(current)
                return
            if s[index] == '(':
                backtrack(index + 1, count, current + '(')
                if count > 0:
                    backtrack(index + 1, count - 1, current)
            elif s[index] == ')':
                backtrack(index + 1, count, current + ')')
                if count < 0:
                    backtrack(index + 1, count + 1, current)
            else:
                backtrack(index + 1, count, current)
        backtrack(0, 0, '')
        return list(res)
```
